<script setup lang="ts">
  import { computed, useId } from 'vue';
  // 在 SVG 中，id 属性必须是全局唯一的。
  // 当你在 index.vue 中遍历生成多个 SvgScore 组件时，每个组件内部都生成了一个 id="dynamic_progress_mask" 的遮罩。浏览器在渲染时，如果发现多个相同 ID 的 SVG 元素，引用方（即 mask="url(#dynamic_progress_mask)"）通常只会指向文档流中找到的第一个 ID。这就是为什么所有仪表盘都显示第一个进度条进度的原因。
  // const maskId = `progress_mask_${Math.random().toString(36).slice(2, 9)}`;
  const maskId = useId();
  // 如果你的页面上有大量的 SVG 滤镜（如代码中的 filter_1, filter_2 等），建议也对这些 ID 进行类似的唯一化处理，否则在复杂页面中，不同组件的阴影效果也可能互相干扰(如果后期加动态的 在处理下)。

  const props = withDefaults(defineProps<{ percentage: string }>(), {
    percentage: '0%',
  });

  const numericValue = computed(() => {
    if (Number.parseFloat(props.percentage) > 100) {
      return 100;
    } else if (Number.parseFloat(props.percentage) < 0) {
      return 0;
    } else {
      return Number.parseFloat(props.percentage);
    }
  });

  // 计算指针旋转角度 (-90deg 到 90deg)
  const needleStyle = computed(() => ({
    transformOrigin: '58px 58px',
    transform: `rotate(${numericValue.value * 1.8 - 90}deg)`,
    transition: 'transform 0.3s ease',
  }));

  // 计算属性：生成动态扇形遮罩路径
  const progressSectorPath = computed(() => {
    const cx = 58.235; // 圆心 X (根据矢量5的数据推导)
    const cy = 58.235; // 圆心 Y
    const r = 60; // 遮罩半径（略大于矢量5）

    // 仪表盘从左侧 (-180度) 开始，顺时针旋转 180 度到右侧
    const startAngle = -180;
    const endAngle = -180 + numericValue.value * 1.8;

    const x1 = cx + r * Math.cos((Math.PI * startAngle) / 180);
    const y1 = cy + r * Math.sin((Math.PI * startAngle) / 180);
    const x2 = cx + r * Math.cos((Math.PI * endAngle) / 180);
    const y2 = cy + r * Math.sin((Math.PI * endAngle) / 180);

    // 当角度超过 180 度时，控制大弧标志
    const largeArcFlag = numericValue.value > 50 ? 1 : 0;

    return `M ${cx} ${cy} L ${x1} ${y1} A ${r} ${r} 0 ${largeArcFlag} 1 ${x2} ${y2} Z`;
  });
</script>

